"use client";

import type * as React from "react";
import { cn } from "@/lib/utils";

export interface KbdProps extends React.HTMLAttributes<HTMLElement> {
  /** Visual size. `sm` for inline within body text, `md` for shortcut hints. */
  size?: "sm" | "md";
}

/**
 * Kbd — keyboard key display. Renders a small key-cap-styled element for
 * keyboard shortcuts and hints. Compose multiple for combos:
 *
 *   <Kbd>⌘</Kbd> <Kbd>K</Kbd>
 *   <Kbd>Ctrl</Kbd> + <Kbd>Shift</Kbd> + <Kbd>P</Kbd>
 */
export function Kbd({
  size = "md",
  className,
  children,
  ...props
}: KbdProps): React.ReactElement {
  return (
    <kbd
      data-slot="kbd"
      data-size={size}
      className={cn(
        "inline-flex items-center justify-center font-sans font-medium tabular-nums text-patch-text-secondary",
        "rounded-[var(--radius-patch-xs)] border-[0.5px] border-patch-border bg-patch-surface",
        "shadow-[inset_0_-1px_0_0_var(--patch-border)]",
        size === "sm" &&
          "h-[18px] min-w-[18px] px-1 text-[length:var(--text-patch-micro)]",
        size === "md" &&
          "h-5 min-w-[20px] px-1.5 text-[length:var(--text-patch-mini)]",
        className,
      )}
      {...props}
    >
      {children}
    </kbd>
  );
}
